 16вҶ’    override fun onFillRequest(request: FillRequest, cancel: CancellationSignal, callback: FillCallback) {
 17вҶ’        val structure = request.fillContexts.lastOrNull()?.structure ?: return callback.onSuccess(null)
 18вҶ’        val db = AppDatabase.get(this)
 19вҶ’        val profiles = db.query("SELECT * FROM profiles ORDER BY createdAt DESC", null).use { c ->
 20вҶ’            val list = mutableListOf<Pair<Long, String>>()
 21вҶ’            while (c.moveToNext()) list.add(c.getLong(0) to c.getString(1))
 22вҶ’            list
 23вҶ’        }
 24вҶ’        if (profiles.isEmpty()) return callback.onSuccess(null)
 25вҶ’
 26вҶ’        // ж”¶йӣҶйЎөйқўдёҠжүҖжңүеҸҜеЎ«е……зҡ„еӯ—ж®ө
 27вҶ’        val fillableFields = mutableListOf<ParsedField>()
 28вҶ’        for (i in 0 until structure.windowNodeCount) {
 29вҶ’            parseNode(structure.getWindowNodeAt(i).rootViewNode, fillableFields)
 30вҶ’        }
 31вҶ’        if (fillableFields.isEmpty()) return callback.onSuccess(null)
 32вҶ’
 33вҶ’        val response = FillResponse.Builder()
 34вҶ’
 35вҶ’        for ((profileId, profileName) in profiles) {
 36вҶ’            val fields = db.fieldDao().getByProfileSync(profileId)
 37вҶ’            if (fields.isEmpty()) continue
 38вҶ’
 39вҶ’            val dataset = Dataset.Builder()
 40вҶ’            var hasMatch = false
 41вҶ’
 42вҶ’            for (pf in fillableFields) {
 43вҶ’                val matched = fields.firstOrNull { matchFieldToHint(it.fieldType, it.label, pf.hints) }
 44вҶ’                if (matched != null) {
 45вҶ’                    val presentation = RemoteViews(packageName, R.layout.autofill_item).apply {
 46вҶ’                        setTextViewText(R.id.tvAutofill, "$profileName: ${matched.label} = ${matched.value}")
 47вҶ’                    }
 48вҶ’                    dataset.setValue(pf.id, AutofillValue.forText(matched.value), presentation)
 49вҶ’                    hasMatch = true
 50вҶ’                } else {
 51вҶ’                    // еҝ…йЎ»дёәжҜҸдёӘеӯ—ж®өи®ҫзҪ®еҖјпјҢеҗҰеҲҷ dataset ж— ж•Ҳпјӣи·іиҝҮжңӘеҢ№й…Қзҡ„
 52вҶ’                }
 53вҶ’            }
 54вҶ’
 55вҶ’            if (hasMatch) {
 56вҶ’                response.addDataset(dataset.build())
 57вҶ’            }
 58вҶ’        }
 59вҶ’
 60вҶ’        try {
 61вҶ’            callback.onSuccess(response.build())
 62вҶ’        } catch (e: Exception) {
 63вҶ’            callback.onSuccess(null)
 64вҶ’        }
 65вҶ’    }
