package com.formfiller.ime

import android.inputmethodservice.InputMethodService
import android.view.LayoutInflater
import android.view.View
import android.view.inputmethod.EditorInfo
import android.view.inputmethod.InputMethodManager
import android.widget.ImageButton
import android.widget.TextView
import androidx.recyclerview.widget.GridLayoutManager
import androidx.recyclerview.widget.LinearLayoutManager
import androidx.recyclerview.widget.RecyclerView
import com.formfiller.R
import com.formfiller.data.AppDatabase
import com.formfiller.data.Field
import com.formfiller.data.Profile

class FieldFillerIME : InputMethodService() {

    private lateinit var db: AppDatabase
    private lateinit var rvFields: RecyclerView
    private lateinit var rvAllFields: RecyclerView
    private lateinit var tvProfile: TextView
    private lateinit var tvHint: TextView
    private lateinit var btnExpand: TextView

    private var profiles = listOf<Profile>()
    private var currentProfileIndex = 0
    private var allFields = listOf<Field>()
    private var expanded = false

    override fun onCreate() {
        super.onCreate()
        db = AppDatabase.get(this)
    }

    override fun onCreateInputView(): View {
        val view = LayoutInflater.from(this).inflate(R.layout.ime_keyboard, null)

        rvFields = view.findViewById(R.id.rvFields)
        rvAllFields = view.findViewById(R.id.rvAllFields)
        tvProfile = view.findViewById(R.id.tvProfile)
        tvHint = view.findViewById(R.id.tvHint)
        btnExpand = view.findViewById(R.id.btnExpand)

        rvFields.layoutManager = LinearLayoutManager(this, LinearLayoutManager.HORIZONTAL, false)
        rvAllFields.layoutManager = GridLayoutManager(this, 3)

        view.findViewById<ImageButton>(R.id.btnPrevProfile).setOnClickListener { switchProfile(-1) }
        view.findViewById<ImageButton>(R.id.btnNextProfile).setOnClickListener { switchProfile(1) }
        view.findViewById<ImageButton>(R.id.btnSwitchKeyboard).setOnClickListener {
            (getSystemService(INPUT_METHOD_SERVICE) as InputMethodManager).showInputMethodPicker()
        }
        btnExpand.setOnClickListener { toggleExpand() }

        loadProfiles()
        return view
    }

    override fun onStartInputView(info: EditorInfo?, restarting: Boolean) {
        super.onStartInputView(info, restarting)
        loadProfiles()
        val hint = info?.hintText?.toString() ?: info?.label?.toString()
        showMatchedFields(hint)
    }

    private fun loadProfiles() {
        try {
            // еҗҢжӯҘжҹҘиҜўпјҢIME дёӯе…Ғи®ё
            profiles = db.profileDao().getAllSync()
            if (profiles.isEmpty()) {
                tvProfile.text = "ж— жЎЈжЎҲ"
                allFields = emptyList()
                tvHint.text = "иҜ·еңЁдё»еә”з”ЁдёӯеҜје…Ҙж–ҮжЎЈ"
            } else {
                if (currentProfileIndex >= profiles.size) currentProfileIndex = 0
                val p = profiles[currentProfileIndex]
                tvProfile.text = p.name
                allFields = try {
                    db.fieldDao().getByProfileSync(p.id)
                } catch (e: Exception) {
                    emptyList()
                }
                tvHint.text = "${allFields.size} дёӘеӯ—ж®ө"
            }
        } catch (e: Exception) {
            tvProfile.text = "еҠ иҪҪеӨұиҙҘ"
            allFields = emptyList()
            tvHint.text = "иҜ·йҮҚеҗҜиҫ“е…Ҙжі•"
        }
    }

    private fun showMatchedFields(hint: String?) {
        val matched = FieldMatcher.match(hint, allFields)
        val adapter = FieldChipAdapter(matched) { field -> commitField(field) }
        rvFields.adapter = adapter
        rvAllFields.adapter = FieldChipAdapter(allFields) { field -> commitField(field) }
    }

    private fun commitField(field: Field) {
        try {
            val value = field.value ?: ""
            if (value.isNotEmpty()) {
                currentInputConnection?.commitText(value, 1)
            }
        } catch (e: Exception) {
            // йқҷй»ҳеӨ„зҗҶй”ҷиҜҜпјҢйҒҝе…Қеҙ©жәғ
        }
    }

    private fun switchProfile(delta: Int) {
        if (profiles.isEmpty()) return
        try {
            currentProfileIndex = (currentProfileIndex + delta + profiles.size) % profiles.size
            val p = profiles[currentProfileIndex]
            tvProfile.text = p.name
            allFields = db.fieldDao().getByProfileSync(p.id)
            tvHint.text = "${allFields.size} дёӘеӯ—ж®ө"
            showMatchedFields(currentInputEditorInfo?.hintText?.toString())
        } catch (e: Exception) {
            // йқҷй»ҳеӨ„зҗҶеҲҮжҚўй”ҷиҜҜ
        }
    }

    private fun toggleExpand() {
        expanded = !expanded
        rvAllFields.visibility = if (expanded) View.VISIBLE else View.GONE
        btnExpand.text = if (expanded) "ж”¶иө· в–ј" else "еұ•ејҖ в–І"
    }
}

package com.formfiller.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase

@Database(entities = [Profile::class, Field::class], version = 1)
abstract class AppDatabase : RoomDatabase() {
    abstract fun profileDao(): ProfileDao
    abstract fun fieldDao(): FieldDao

    companion object {
        @Volatile private var instance: AppDatabase? = null

        fun get(context: Context): AppDatabase =
            instance ?: synchronized(this) {
                instance ?: Room.databaseBuilder(
                    context.applicationContext, AppDatabase::class.java, "formfiller.db"
                ).allowMainThreadQueries().build().also { instance = it }
            }
    }
}

package com.formfiller.data

import androidx.room.*

@Dao
interface ProfileDao {
    @Query("SELECT * FROM profiles ORDER BY createdAt DESC")
    suspend fun getAll(): List<Profile>

    @Query("SELECT * FROM profiles ORDER BY createdAt DESC")
    fun getAllSync(): List<Profile>

    @Insert
    suspend fun insert(profile: Profile): Long

    @Delete
    suspend fun delete(profile: Profile)

    @Update
    suspend fun update(profile: Profile)
}

@Dao
interface FieldDao {
    @Query("SELECT * FROM fields WHERE profileId = :profileId")
    suspend fun getByProfile(profileId: Long): List<Field>

    @Query("SELECT * FROM fields")
    fun getAllSync(): List<Field>

    @Query("SELECT * FROM fields WHERE profileId = :profileId")
    fun getByProfileSync(profileId: Long): List<Field>

    @Insert
    suspend fun insert(field: Field): Long

    @Insert
    suspend fun insertAll(fields: List<Field>)

    @Delete
    suspend fun delete(field: Field)

    @Update
    suspend fun update(field: Field)

    @Query("DELETE FROM fields WHERE profileId = :profileId")
    suspend fun deleteByProfile(profileId: Long)
}

